def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    n = len(bins)
    priorities = np.full(n, np.inf)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity * 1.2:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        base_score = 0
        if ratio == 1:
            base_score = 0
        elif ratio < 0.3:
            base_score = (0.3 - ratio) ** 3 + 0.15
        elif ratio < 0.75:
            base_score = (0.75 - ratio) ** 2
        else:
            base_score = abs(np.log(ratio)) * (1 + (i % 4) * 0.12)
        adj_factor = 1.0
        if capacity < item * 1.3:
            adj_factor *= 2.2
        elif capacity < item * 1.8:
            adj_factor *= 1.7
        elif capacity < item * 2.5:
            adj_factor *= 1.3
        penalty = 0
        for offset in range(-4,5):
            idx = i + offset
            if idx < 0 or idx >= n or offset == 0:
                continue
            neighbor = bins[idx]
            if neighbor <= 0:
                continue
            overlap_ratio = item / neighbor
            if 0 < overlap_ratio < 1:
                weight = 1 / (abs(offset) + 1)
                penalty += weight * (1 - overlap_ratio) ** 3
            elif overlap_ratio == 1:
                penalty += 0.2 / (abs(offset) + 1)
        penalty /= 7
        extra_penalty = 0
        for j in range(n):
            if j == i:
                continue
            dist = abs(j - i)
            if dist > 5:
                continue
            cap = bins[j]
            if cap <= 0:
                continue
            diff = abs(capacity - cap) / max(capacity, cap)
            if diff > 0.4 and dist <= 3:
                extra_penalty += diff / (dist+1)
        score = (base_score * adj_factor) + penalty + extra_penalty
        if score < 0:
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        min_priority = np.min(finite_priorities)
        max_priority = np.max(finite_priorities)
        range_priority = max_priority - min_priority if max_priority != min_priority else 1
        for i in range(n):
            if not np.isfinite(priorities[i]):
                priorities[i] = max_priority * 2
            else:
                norm_score = (priorities[i] - min_priority) / range_priority
                decay = np.exp(-i / (n / 3))
                priorities[i] = norm_score * decay
    else:
        priorities.fill(np.inf)
    return priorities
